   Subelement TurbineReynoldsEffects S_Re {
      Table s_effRe(real RNI) {
         RNI = { 0.3000, 0.3699, 0.4560, 0.5621, 0.6930, 0.8544, 1.0000, 1.0534, 1.2986, 1.6010, 1.9738, 2.4334, 3.0000 }
